:root {
  --bg: #ffffff;
  --border: #e2e8f0;
  --title-color: #1e293b;
  --week-color: #64748b;
  --week-bg: #f1f5f9;
  --habit-name-color: #334155;
  --day-bg: #f1f5f9;
  --day-color: #94a3b8;
  --done-bg: #6366f1;
  --done-color: #ffffff;
  --footer-bg: #f8fafc;
  --footer-label: #64748b;
  --footer-score: #6366f1;
  --score-track: #e2e8f0;
  --score-fill: #6366f1;
  --divider: #e2e8f0;
}

.tracker {
  background: var(--bg);
  border: 1.5px solid var(--border);
  border-radius: 16px;
  width: 320px;
  padding: 0;
  overflow: hidden;
}

.tracker-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 18px 20px 16px 20px;
  border-bottom: 1.5px solid var(--divider);
}

.tracker-title {
  font-size: 17px;
  font-weight: 700;
  color: var(--title-color);
  letter-spacing: -0.3px;
}

.tracker-week {
  font-size: 12px;
  font-weight: 600;
  color: var(--week-color);
  background: var(--week-bg);
  border-radius: 20px;
  padding: 4px 10px;
}

.habit-list {
  padding: 8px 0;
}

.habit-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 20px;
}

.habit-name {
  font-size: 13px;
  font-weight: 600;
  color: var(--habit-name-color);
  width: 68px;
}

.habit-days {
  display: flex;
  gap: 5px;
}

.day {
  width: 28px;
  height: 28px;
  border-radius: 8px;
  background: var(--day-bg);
  color: var(--day-color);
  font-size: 11px;
  font-weight: 600;
  display: flex;
  align-items: center;
  justify-content: center;
}

.day.done {
  background: var(--done-bg);
  color: var(--done-color);
}

.tracker-footer {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 14px 20px;
  background: var(--footer-bg);
  border-top: 1.5px solid var(--divider);
}

.footer-label {
  font-size: 12px;
  font-weight: 600;
  color: var(--footer-label);
  white-space: nowrap;
}

.score-bar {
  flex: 1;
  height: 7px;
  background: var(--score-track);
  border-radius: 99px;
  overflow: hidden;
}

.score-fill {
  width: 71%;
  height: 100%;
  background: var(--score-fill);
  border-radius: 99px;
}

.footer-score {
  font-size: 13px;
  font-weight: 700;
  color: var(--footer-score);
}
